const seasons = [
  "2023-24",
  "2022-23",
  "2021-22"
];

return seasons.map(season => ({
  json: { season }
}));

function slugify(text) {
  return String(text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

const output = [];

for (const item of items) {
  const raw = item.json.data || item.json.body || "";

  const text = String(raw)
    .replace(/\\n/g, "\n")
    .replace(/\r/g, "\n");

  let seasonRaw =
    item.json.season ||
    item.json.input?.season ||
    item.json.params?.season ||
    null;

  if (!seasonRaw) {
    const seasonMatch = text.match(/\b(20\d{2})\/(\d{2})\b/);
    if (seasonMatch) {
      seasonRaw = `${seasonMatch[1]}-${seasonMatch[2]}`;
    }
  }

  const season = seasonRaw ? seasonRaw.replace("-", "/") : null;

  const lines = text
    .split("\n")
    .map(l => l.trim())
    .filter(Boolean);

  let currentMatchday = null;

  for (let line of lines) {

    // detectar jornada
    const md = line.match(/Matchday\s+(\d+)/i);
    if (md) {
      currentMatchday = Number(md[1]);
      continue;
    }

    // ignorar basura
    if (
      line.startsWith("=") ||
      line.startsWith("#") ||
      line.startsWith("[") ||
      /^primera division/i.test(line)
    ) continue;

    // eliminar fecha tipo "Fri Aug/11"
    line = line.replace(/^[A-Z][a-z]{2}\s+[A-Z][a-z]{3}\/\d{1,2}\s+/, "");

    // regex REAL para openfootball
    const match = line.match(
      /^(?:(\d{1,2}\.\d{2})\s+)?(.+?)\s+(\d+)-(\d+)(?:\s+\(\d+-\d+\))?\s+(.+)$/
    );

    if (!match) continue;

    const kickoff = match[1] || null;
    let homeTeam = match[2].trim();
    const homeScore = Number(match[3]);
    const awayScore = Number(match[4]);
    let awayTeam = match[5].trim();

    output.push({
      json: {
        season,
        matchday: currentMatchday,
        kickoff_text: kickoff,
        utc_date: null,
        home_team_name: homeTeam,
        away_team_name: awayTeam,
        home_team_slug_guess: slugify(homeTeam),
        away_team_slug_guess: slugify(awayTeam),
        home_score: homeScore,
        away_score: awayScore,
        status: "finished",
        source: "openfootball",
        source_id: [
          "openfootball",
          seasonRaw || "noseason",
          currentMatchday || "nomd",
          slugify(homeTeam),
          slugify(awayTeam),
          kickoff || "notime"
        ].join("-")
      }
    });
  }
}

return output;

function slugify(text) {
