const merged = items.map(i => i.json);

const teamsContainer = merged.find(i => Array.isArray(i.teams));
const teams = teamsContainer?.teams || [];
const matches = merged.filter(i => !Array.isArray(i.teams));

const teamsBySlug = new Map();
const teamsByNameSlug = new Map();

for (const team of teams) {
  const slug = slugify(team.slug || "");
  const nameSlug = slugify(team.name || "");

  if (slug) teamsBySlug.set(slug, team);
  if (nameSlug) teamsByNameSlug.set(nameSlug, team);
}

function resolveTeam(rawSlugGuess, rawName) {
  let guess = slugify(rawSlugGuess || rawName || "");

  guess = aliasMap[guess] || guess;

  return (
    teamsBySlug.get(guess) ||
    teamsByNameSlug.get(guess) ||
    teamsBySlug.get(aliasMap[slugify(rawName || "")] || "") ||
    teamsByNameSlug.get(slugify(rawName || "")) ||
    null
  );
}

return matches.map(match => {
  const homeTeam = resolveTeam(match.home_team_slug_guess, match.home_team_name);
  const awayTeam = resolveTeam(match.away_team_slug_guess, match.away_team_name);

  return {
    json: {
      ...match,
      competition_id: "a6d5fa20-1a02-4aa8-bd08-707a87c488d6",
      home_team_id: homeTeam ? homeTeam.id : null,
      away_team_id: awayTeam ? awayTeam.id : null
    }
  };
});

const chunkSize = 50;
const rows = items.map(i => i.json);

const cleaned = rows.map(r => ({
  competition_id: r.competition_id,
  season: r.season,
  matchday: r.matchday ?? null,
  home_team_id: r.home_team_id,
  away_team_id: r.away_team_id,
  stadium_id: null,
  kickoff_at: r.utc_date ?? null,
  home_score: r.home_score ?? null,
  away_score: r.away_score ?? null,
  status: r.status,
  source: "openfootball",
  source_id: r.source_id
}));

const batches = [];
for (let i = 0; i < cleaned.length; i += chunkSize) {
  batches.push({
    json: {
      batch: cleaned.slice(i, i + chunkSize)
    }
  });
}

return batches;

const out = [];

for (const item of items) {
  const j = item.json;

  if (!j.home_team_id && j.home_team_name) {
    out.push({
      json: {
        name: j.home_team_name,
        slug: j.home_team_slug_guess || null,
        external_id: null,
        source: "openfootball",
        source_id: j.home_team_slug_guess || null
      }
    });
  }

  if (!j.away_team_id && j.away_team_name) {
    out.push({
      json: {
        name: j.away_team_name,
        slug: j.away_team_slug_guess || null,
        external_id: null,
        source: "openfootball",
        source_id: j.away_team_slug_guess || null
      }
    });
  }
}

return out;

const seen = new Set();
const unique = [];

for (const item of items) {
  const key = (item.json.slug || item.json.name || "").toLowerCase().trim();
  if (!key) continue;

  if (!seen.has(key)) {
    seen.add(key);
    unique.push({
      json: item.json
    });
  }
}

return unique;

return [
  {
    json: {
      payload: items.map(i => ({
        name: i.json.name,
        slug: i.json.slug,
        country_id: "37f46503-683b-4aa0-be0b-dea6d5db4b50",
        source: "openfootball",
        source_id: i.json.source_id ?? null,
        external_id: null
      }))
    }
  }
];
